import { schemaTask } from "@trigger.dev/sdk";
import { z } from "zod";

export const basicZodTask = schemaTask({
  id: "basic-zod-task-basic_task_zod__Weg8NDa",
  schema: z.object({
    name: z.string(),
    age: z.number(),
  }),
  retry: {
    maxAttempts: 3,
  },
  run: async ({ name, age }) => {
    return `Hello ${name}, you are ${age} years old!`;
  },
});

